import React, { useState, useEffect, useContext } from "react";
import { AuthContext } from "./AuthContext";
import { Login } from "./Login"

const Header = () => {
    const [windowWidth, setWindowWidth] = useState(window.innerWidth);
    const [DisplayLogin, setShowLogin] = useState(false);
    const [username, setUsername] = useState(null);
    const [formUser, setFormUser] = useState("");
    const [formPass, setFormPass] = useState("");
    const [isSignup, setIsSignup] = useState(false);
    const [error, setError] = useState("");

    const handleChange = (e) => {
        const { name, value } = e.target;
        setFormUser((prev) => ({ ...prev, [name]: value }));
    };

    const handleSubmit = async (e) => {
        e.preventDefault();
        setError("");
        if (isSignup) {
            const result = await signup(formUser.email, formUser.password, formUser.username);
            if (!result.success) setError(result.message);
            else setShowModal(false);
        } else {
            const result = await login(formUser.email, formUser.password);
            if (!result.success) {
                if (result.newUser) setIsSignup(true);
                else setError(result.message);
            } else {
                setShowModal(false);
            }
        }
    };

    useEffect(() => {
        const handleResize = () => setWindowWidth(window.innerWidth);
        window.addEventListener("resize", handleResize);
        return () => window.removeEventListener("resize", handleResize);
    }, []);

    const showLogin = windowWidth > 800;
    const showTalks = windowWidth > 700;
    const showForms = windowWidth > 600;
    const showClubs = windowWidth > 500;
    const showEvents = windowWidth > 400;

    const handleLogin = () => {
        fetch("/api/auth/login", {
            method: "POST",
            headers: { "Content-Type": "application/json" },
            body: JSON.stringify({ username: formUser, password: formPass })
        })
            .then(res => res.json())
            .then(data => {
                if (data.status === "success") {
                    setUsername(data.username);
                    setShowLogin(false);
                } else {
                    alert(data.message);
                }
            });
    };

    const handleLogout = () => {
        setUsername(null);
    };

    return (
        <header style={styles.header}>
            <div style={styles.container}>
                {/* Logo */}
                <div style={styles.logo}>MyLogo</div>

                {/* Search Bar */}
                <input type="text" placeholder="Search..." style={styles.search} />

                {/* Navigation */}
                <nav style={styles.nav}>
                    {showEvents && <a href="#events" style={styles.navLink}>Events</a>}
                    {showClubs && <a href="#clubs" style={styles.navLink}>Clubs</a>}
                    {showForms && <a href="#forms" style={styles.navLink}>Forms</a>}
                    {showTalks && <a href="#talks" style={styles.navLink}>Talks</a>}
                </nav>

                <div>
                    {username ? (
                        <>
                            <span>Welcome, {username}</span>
                            <button onClick={handleLogout} style={{ marginLeft: "10px" }}>Logout</button>
                        </>
                    ) : (
                        <button onClick={() => setShowLogin(true)}>Login</button>
                    )}
                </div>

                {/* Modal */}
                {DisplayLogin && (
                    <div style={styles.modalOverlay}>
                        <div style={styles.modalContent}>
                            <h3>{isSignup ? "Sign Up" : "Login"}</h3>
                            {error && <p style={{color: "red"}}>{error}</p>}
                            <form onSubmit={handleSubmit}>
                                {isSignup && (
                                    <input
                                        name="username"
                                        placeholder="Username"
                                        value={form.username}
                                        onChange={handleChange}
                                        required
                                        style={styles.input}
                                    />
                                )}
                                <input
                                    name="email"
                                    type="email"
                                    placeholder="Email"
                                    value={form.email}
                                    onChange={handleChange}
                                    required
                                    style={styles.input}
                                />
                                <input
                                    name="password"
                                    type="password"
                                    placeholder="Password"
                                    value={form.password}
                                    onChange={handleChange}
                                    required
                                    style={styles.input}
                                />
                                <div style={{ display: "flex", justifyContent: "flex-end" }}>
                                    <button type="submit" style={styles.submitBtn}>
                                        {isSignup ? "Sign Up" : "Login"}
                                    </button>
                                    <button
                                        type="button"
                                        onClick={() => setShowModal(false)}
                                        style={styles.cancelBtn}
                                    >
                                        Cancel
                                    </button>
                                </div>
                            </form>
                        </div>
                    </div>
                )}
            </div>
        </header>
    );
};

const styles = {
    header: {
        position: "fixed",
        top: 0,
        left: 0,
        width: "100%",
        backgroundColor: "#041E42",
        color: "white",
        zIndex: 1000,
    },
    container: {
        maxWidth: "1200px",
        margin: "0 auto",
        display: "flex",
        alignItems: "center",
        justifyContent: "space-between",
        padding: "10px 20px",
    },
    logo: { fontWeight: "bold", fontSize: "1.5rem", marginRight: "20px" },
    search: {
        backgroundColor: "#6f7680",
        flexGrow: 1,
        margin: "0 20px",
        padding: "5px 10px",
        fontSize: "1rem",
        borderRadius: "4px",
        border: "none",
        color: "white",
    },
    nav: { display: "flex", gap: "15px", whiteSpace: "nowrap" },
    navLink: {
        color: "white",
        textDecoration: "none",
        fontWeight: "500",
        padding: "0 10px",
        borderRight: "1px solid gray",
    },
    loginBtn: {
        marginLeft: "20px",
        padding: "8px 15px",
        fontSize: "1rem",
        borderRadius: "4px",
        backgroundColor: "#D50032",
        color: "white",
        border: "none",
        cursor: "pointer",
    },
    logoutBtn: {
        marginLeft: "10px",
        padding: "8px 15px",
        fontSize: "1rem",
        borderRadius: "4px",
        backgroundColor: "#D50032",
        color: "white",
        border: "none",
        cursor: "pointer",
    },
    modalOverlay: {
        position: "fixed",
        top: 0,
        left: 0,
        right: 0,
        bottom: 0,
        backgroundColor: "rgba(0,0,0,0.5)",
        display: "flex",
        justifyContent: "center",
        alignItems: "center",
    },
    modalContent: { backgroundColor: "#fff", padding: "20px", borderRadius: "6px", width: "400px", maxWidth: "90%" },
    input: { width: "100%", padding: "8px", marginBottom: "10px", borderRadius: "4px", border: "1px solid #ccc" },
    submitBtn: { padding: "8px 12px", marginRight: "10px", backgroundColor: "#D50032", color: "#fff", border: "none", borderRadius: "4px", cursor: "pointer" },
    cancelBtn: { padding: "8px 12px", backgroundColor: "#ccc", color: "#000", border: "none", borderRadius: "4px", cursor: "pointer" },
};

export default Header;
